/**
 * Generated by `createservice acquiring.RecordManualRentPaymentService`
 */

const { GQLError, GQLErrorCode: { BAD_USER_INPUT } } = require('@open-condo/keystone/errors')
const { checkDvAndSender } = require('@open-condo/keystone/plugins/dvAndSender')
const { GQLCustomSchema } = require('@open-condo/keystone/schema')

const access = require('@condo/domains/acquiring/access/RecordManualRentPaymentService')
const { recordManualRentPayment } = require('@condo/domains/acquiring/utils/serverSchema')
const { DV_VERSION_MISMATCH, REQUIRED, WRONG_FORMAT } = require('@condo/domains/common/constants/errors')

const ERRORS = {
    DV_VERSION_MISMATCH: {
        mutation: 'recordManualRentPayment',
        variable: ['data', 'dv'],
        code: BAD_USER_INPUT,
        type: DV_VERSION_MISMATCH,
        message: 'Wrong value for data version number',
    },
    WRONG_SENDER_FORMAT: {
        mutation: 'recordManualRentPayment',
        variable: ['data', 'sender'],
        code: BAD_USER_INPUT,
        type: WRONG_FORMAT,
        message: 'Invalid format of "sender" field value. {details}',
        correctExample: '{ "dv": 1, "fingerprint": "uniq-device-or-container-id" }',
        messageInterpolation: { details: 'Please, check the example for details' },
    },
    REQUIRED_AMOUNT: {
        mutation: 'recordManualRentPayment',
        variable: ['data', 'amount'],
        code: BAD_USER_INPUT,
        type: REQUIRED,
        message: 'Amount is required for manual rent payment recording',
    },
}

const RecordManualRentPaymentService = new GQLCustomSchema('RecordManualRentPaymentService', {
    types: [
        {
            access: true,
            type: 'input RecordManualRentPaymentInput { dv: Int!, sender: SenderFieldInput!, organization: OrganizationWhereUniqueInput!, tenant: ResidentWhereUniqueInput!, occupancy: OccupancyWhereUniqueInput, property: PropertyWhereUniqueInput, rentalUnit: RentalUnitWhereUniqueInput, amount: String!, paymentMethod: String!, reference: String, depositedDate: String, confirmedAt: String, purpose: String, posReceiptUrl: String }',
        },
        {
            access: true,
            type: 'type RecordManualRentPaymentOutput { payment: Payment!, allocations: [PaymentAllocation!]!, receipt: PaymentReceipt!, ledgerBalance: String! }',
        },
    ],

    mutations: [
        {
            access: access.canRecordManualRentPayment,
            schema: 'recordManualRentPayment(data: RecordManualRentPaymentInput!): RecordManualRentPaymentOutput',
            resolver: async (parent, args, context) => {
                const { data } = args

                checkDvAndSender(data, ERRORS.DV_VERSION_MISMATCH, ERRORS.WRONG_SENDER_FORMAT, context)

                if (!data.amount) {
                    throw new GQLError(ERRORS.REQUIRED_AMOUNT, context)
                }

                return await recordManualRentPayment(context, data)
            },
        },
    ],
})

module.exports = {
    RecordManualRentPaymentService,
}